INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('411d4b82-ffd0-49fa-8d65-6fcc9caad2a6', 'Database', 'Database operations, migrations, and troubleshooting', '#3B82F6', '🗄️', '{"pattern":"[Action verb] + [database/table/operation] + [condition or scope]","example":"Restore PostgreSQL database from S3 backup after data corruption","whenToUse":"Use for database-related procedures: backups, restores, migrations, performance","contentHints":"Start with prerequisites (access, tools, permissions). List exact commands with expected output. Include rollback steps. Add verification queries to confirm success."}', 1, 0, '2026-03-20T09:03:25.895Z', '2026-03-20T09:03:25.895Z');
