INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Runbook', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'Standard operating procedures and operational playbooks', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Write an action-oriented title that a stressed on-call engineer can scan in seconds. Follow the system-specific pattern. Example: \"Restart Kafka consumer group after lag spike\""},"content":{"tips":"Write for someone executing this at 3 AM during an incident. Every step must be copy-pasteable. Include expected output for verification. Start with prerequisites and end with a verification checklist."},"formatting":["Numbered lists: every procedural step must be numbered sequentially","Code blocks: exact commands with expected output, always include shell type","Tables: environment variables, service endpoints, escalation contacts","Headings: Prerequisites, Procedure, Verification, Rollback, Escalation","Bold: critical warnings, irreversible steps, and timeout values","Blockquotes: caution notes for steps that can cause downtime"],"avoid":["Vague steps like \"check the logs\" without specifying which logs or commands","Missing rollback procedures for destructive operations","Outdated hostnames, endpoints, or commands","Prose paragraphs where a numbered checklist would be clearer"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":15,"max":200},"content":{"min":200,"max":20000},"sourceAi":{"min":1,"max":100}}', datetime('now'));
